const raw = $input.all()[0].json.choices[0].message.content;
let c;
try { c = JSON.parse(raw); } catch(e) { c = { esi_level: 3, acuity: 'medium', primary_flag: 'parse_error', complaint_summary: 'parse failed' }; }
const esi = Number(c.esi_level) || 3;
const tier = esi <= 2 ? 'critical' : esi === 3 ? 'urgent' : 'low';
return [{ json: { tier: tier, esi_level: esi, acuity: String(c.acuity || 'medium'), primary_flag: String(c.primary_flag || 'none'), complaint_summary: String(c.complaint_summary || '') } }];
